var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 시간 뒤","JPN":"数時間後","ENG":"A few hours later","TWN":"幾小時後","SCN":"几小时后","DEU":"A few hours later","FRA":"A few hours later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님, 제2 탐험대로부터 연락이 왔습니다.","JPN":"シニア、第2探検隊から連絡がありました。","ENG":"Senior, a report has come in from the Second Expeditionary Force.","TWN":"你好，Senior，第二探險隊發來消息了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"지시하신 대로, 에어리어 알파, 세타… 모두 탐색을 마쳤습니디만…….","JPN":"ご指示通り、エリアアルファ、シータ……すべて探索を終えましたが……","ENG":"Per your orders, they've finished scouting Areas Alpha and Theta... but...","TWN":"按照指示，區域阿爾法、希塔……都已經探索完畢……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님께서 말씀하신 장소는 특정할 수 없었다고 합니다.","JPN":"シニアが示した場所は特定できなかったとのことです。","ENG":"They couldn't pinpoint the location you mentioned, sir.","TWN":"但沒找到你說的地點。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"흐음, 그런가…….","JPN":"ふむ、そうか……","ENG":"Hmm, I see...","TWN":"嗯，是嗎……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다면 역시 이번에도 다다를 수 없는 건가…….","JPN":"ということは、やはり今回もたどり着けないということじゃな……","ENG":"So once again, it seems we can't reach it...","TWN":"這次果然還是無法到達嗎……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸, 천공섬 탐색을 시작한 지 제법 시간이 지났습니다.","JPN":"カン、天空島の探索を始めてから、かなりの時間が経過しました。","ENG":"Khan, it's been quite some time since we began exploring the floating island.","TWN":"坎，開始探索天空島已經有一段時間了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"카운터인 저는 그렇다 쳐도, 대원들의 이터니움 실드와 공기통이 한계입니다.","JPN":"カウンターの私はともかく、隊員たちのエタニウムシールドと酸素ボンベはもう限界です。","ENG":"I may endure it as a Counter, but the squad's Eternium shields and air tanks are reaching their limits.","TWN":"我是制裁者無所謂，但隊員們的永恆之金盾和氧氣瓶已經到極限了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"물자가 부족한 상황에서 고위 침식체와 마주하면 대처가 어렵습니다.","JPN":"物資が不足している状況で、高レベルの侵食体に遭遇すると対処が難しくなります。","ENG":"If we run into high-tier C.O.s with supplies running low, we won't be able to cope.","TWN":"在物資匱乏的情況下，面對高危侵蝕體會很危險。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이쯤에서 관리국으로 복귀하시죠.","JPN":"この辺で管理局へ帰還しましょう。","ENG":"We should return to the Administration for now.","TWN":"回管理局吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"슬슬 타임 리미트인가…….","JPN":"そろそろタイムリミットか……","ENG":"So the time limit's upon us...","TWN":"極限了嗎……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"알겠네. 아쉽지만 어쩔 수 없지. 기회가 오늘만 있는 것도 아니니까.","JPN":"分かった。残念だが仕方あるまい。チャンスが今日しかないわけでもないからのう。","ENG":"Very well. A shame, but there'll be other chances.","TWN":"好吧。雖然很可惜，但也沒辦法。以後還有機會。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자자, 오늘 탐험은 여기까지라네!","JPN":"さあ、今日の探検はここまでじゃ！","ENG":"All right, we'll end today's expedition here!","TWN":"好了，今天的探險就到這裡！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"모두 수고했네. 탐험 대원들은 지상으로 돌아갈 준비를……","JPN":"皆、ご苦労じゃった。探検隊員は地上に戻る準備を……","ENG":"Good work, everyone. Prepare to return to the surface–","TWN":"大家辛苦了，準備返回地面……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"음!?","JPN":"む！？","ENG":"Hm?!","TWN":"嗯！?"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"무슨 일이십니까?","JPN":"どうされました？","ENG":"What is it?","TWN":"有什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"화살촉이 반응하고 있어……?","JPN":"矢じりが反応しておる……？","ENG":"The arrowhead is reacting...?","TWN":"箭矢有反應……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그, 그렇다면… 설마……!?","JPN":"と、ということは……まさか……！？","ENG":"C-could it be...? No, impossible...?!","TWN":"難…難道是…？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 갑자기 어디 가십니까!","JPN":"カン！　急にどこに行くのですか！","ENG":"Khan! Where are you going all of a sudden?!","TWN":"坎！你要去哪裡！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"제기랄, 저 빌어먹을 노인네가 또……!","JPN":"ちくしょう、あのクソじじい……またか！","ENG":"Damn it, that blasted geezer is at it again...!","TWN":"該死的，那個老傢伙又……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"시니어님을 모시고 오겠다! 모든 대원은 현재 위치를 사수하고, 잠시 대기하도록……!","JPN":"シニアを連れてくる！　全隊員は持ち場を守り、しばらく待機するように……！","ENG":"I'll bring the Senior back! All units, hold your positions and stand by...!","TWN":"我去找Senior！所有隊員堅守崗位等我回來…！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"마, 말도 안 돼… 화살촉의 떨림이 멈추지 않아…….","JPN":"ま、まさか……矢じりの震えが止まらん……","ENG":"I-impossible... the arrowhead's trembling won't stop...","TWN":"怎，怎麼可能…箭矢一直在動……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇다면… 이곳 어딘가에…….","JPN":"つまり……このどこかに……","ENG":"Then that means... somewhere here...","TWN":"那樣的話……就在這附近的某個地方……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"어디냐… 대체 어디 있는 게냐……","JPN":"どこじゃ……いったいどこにあるんじゃ……","ENG":"Where is it...? Where could it be...?","TWN":"到底……在哪裡……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"음!?","JPN":"む！？","ENG":"Hm?!","TWN":"嗯！？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칸! 여기서 뭐하시는 겁니까! 관리국으로 돌아가기로 하지 않았습니까……!","JPN":"カン！　何をしているんですか！　管理局に戻ると言ったではないですか……！","ENG":"Khan! What are you doing out here?! We agreed to return to the Administration...!","TWN":"坎！你在這裡做什麼！不是說好要回管理局嗎……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"웨이드! 이걸 보게! 화살촉이 반응하고 있어!","JPN":"ウェイド！　これを見ろ！　矢じりが反応しておる！","ENG":"Wade! Look! The arrowhead's reacting!","TWN":"韋德！快看這個！箭矢在反應！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"잠깐, 화살촉이라고요……?","JPN":"矢じりですと……？","ENG":"Huh? The arrowhead...?","TWN":"等等，箭矢……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};